# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule MyAppWeb.PostLive do
  use Phoenix.LiveView

  def mount(_session, socket) do
    {:ok, assign(socket, :posts, [])}
  end

  def render(assigns) do
    ~H"""
      <div>
        <%= for post <- @posts do %>
          <div>
            <%= raw(post.content) %>
          </div>
        <% end %>
      </div>

      <form phx-submit="create_post">
        <textarea phx-debounce="500" name="content"></textarea>
        <button>Post</button>
      </form>
    """
  end

  def handle_event("create_post", %{"post" => %{"content" => content}}, socket) do
    new_post = %{socket.assigns.posts, content: content}
    {:noreply, assign(socket, :posts, [new_post | socket.assigns.posts])}
  end
end